import React, { useEffect, useMemo, useState } from "react";

const STORAGE_KEY = "slice-board-v1";
const LEGACY_STORAGE_KEYS = ["joey-fidelity-pie-planner-v1"];
const LOGO_PNG = "data:image/png;base64,";
const PIZZA_PNG = "data:image/png;base64,";
const BADGE_IMAGES = {
  basil: "data:image/png;base64,",
  pepperoni: "data:image/png;base64,",
  mushroom: "data:image/png;base64,",
  olive: "data:image/png;base64,",
  pepper: "data:image/png;base64,",
  onion: "data:image/png;base64,",
  plain: "data:image/png;base64,",
  sauce: "data:image/png;base64,",
} as const;

type PlanKey = "current" | "next";
type Tab = "chart" | "edit" | "tools";
type Topping = keyof typeof BADGE_IMAGES;
type Slice = { id: string; name: string; amount: number; topping?: Topping; color?: string };
type Plan = { total: number; sections: Slice[] };
type AppState = { version: number; current: Plan; next: Plan; nextEnabled: boolean; updatedAt?: string };
type Segment = { id: string; label: string; value: number; amount: number; topping: Topping };

const TOPPINGS: Array<{ value: Exclude<Topping, "sauce">; label: string }> = [
  { value: "basil", label: "Basil" },
  { value: "pepperoni", label: "Pepperoni" },
  { value: "mushroom", label: "Mushroom" },
  { value: "olive", label: "Olive" },
  { value: "plain", label: "Plain" },
];

const uid = () => `slice-${Date.now()}-${Math.random().toString(36).slice(2, 7)}`;
const money = (n: number) => new Intl.NumberFormat("en-US", { style: "currency", currency: "USD" }).format(Number.isFinite(n) ? n : 0);
const pct = (n: number) => `${n.toFixed(1)}%`;
const parseMoney = (v: unknown) => { const n = Number.parseFloat(String(v ?? "").replace(/[^0-9.-]/g, "")); return Number.isFinite(n) ? Number(n.toFixed(2)) : 0; };
const isUnassigned = (name: string) => name.trim().toLowerCase() === "unassigned";
const toppingLabel = (t: Topping) => t === "sauce" ? "Sauce only" : TOPPINGS.find((x) => x.value === t)?.label ?? "Plain";
const normalizeTopping = (t: unknown, index: number, name = ""): Topping => {
  if (isUnassigned(name)) return "sauce";
  if (typeof t === "string" && t in BADGE_IMAGES) return t as Topping;
  return TOPPINGS[index % (TOPPINGS.length - 1)].value;
};
const starter = (): Slice[] => [
  { id: uid(), name: "Emergency Fund", amount: 0, topping: "basil" },
  { id: uid(), name: "Unassigned", amount: 0, topping: "sauce" },
  { id: uid(), name: "Bankruptcy", amount: 0, topping: "mushroom" },
];
const normalizePlan = (raw: any, fallback = 0): Plan => ({
  total: parseMoney(raw?.total ?? fallback),
  sections: Array.isArray(raw?.sections) ? raw.sections.map((s: any, i: number) => ({ id: s.id || uid(), name: s.name || `Section ${i + 1}`, amount: parseMoney(s.amount), color: s.color, topping: normalizeTopping(s.topping, i, s.name) })) : [],
});
const fresh = (): AppState => ({ version: 11, current: normalizePlan({ total: 0, sections: starter() }), next: normalizePlan({ total: 0, sections: starter() }), nextEnabled: true });
const normalizeState = (raw: any): AppState => raw && (raw.current || raw.next)
  ? { version: 11, current: normalizePlan(raw.current), next: normalizePlan(raw.next), nextEnabled: raw.nextEnabled ?? true, updatedAt: raw.updatedAt }
  : { version: 11, current: normalizePlan(raw), next: normalizePlan({ total: 0, sections: [] }), nextEnabled: true, updatedAt: raw?.updatedAt };
const load = () => { try { const p = localStorage.getItem(STORAGE_KEY); if (p) return normalizeState(JSON.parse(p)); for (const k of LEGACY_STORAGE_KEYS) { const x = localStorage.getItem(k); if (x) return normalizeState(JSON.parse(x)); } } catch { return fresh(); } return fresh(); };
const chartState = (plan: Plan) => {
  const positive = plan.sections.filter((s) => s.amount > 0);
  const allocated = positive.reduce((sum, s) => sum + s.amount, 0);
  const remaining = Math.max(0, plan.total - allocated);
  const template = plan.total <= 0 && allocated <= 0 && plan.sections.length > 0;
  const segments: Segment[] = template
    ? plan.sections.map((s, i) => ({ id: s.id, label: s.name, value: 1, amount: 0, topping: normalizeTopping(s.topping, i, s.name) }))
    : positive.map((s, i) => ({ id: s.id, label: s.name, value: s.amount, amount: s.amount, topping: normalizeTopping(s.topping, i, s.name) }));
  if (!template && remaining > 0) segments.push({ id: "remaining", label: "Remaining", value: remaining, amount: remaining, topping: "plain" });
  return { segments, allocated, remaining, total: Math.max(plan.total, allocated, template ? segments.length : 0), template };
};
function cls(...parts: Array<string | false | undefined>) { return parts.filter(Boolean).join(" "); }

function Logo() { return <img src={LOGO_PNG} alt="Slice Board pizza logo" className="h-16 w-16 shrink-0 rounded-[19px] object-cover shadow-[0_0_22px_rgba(244,146,34,.28)]" />; }
function Badge({ topping }: { topping: Topping }) { return <img src={BADGE_IMAGES[topping]} alt={`${toppingLabel(topping)} topping`} className="h-12 w-12 shrink-0 rounded-full object-cover" />; }
function Metric({ label, value, tone = "gold" }: { label: string; value: string; tone?: "gold" | "ember" }) { return <div className={cls("min-w-0 rounded-[22px] border px-3 py-3", tone === "ember" ? "border-orange-700/35 bg-[#24100b]/80" : "border-amber-700/30 bg-[#201305]/78")}><div className="truncate text-[10px] uppercase tracking-[.18em] text-[#d6a934]">{label}</div><div className="mt-2 truncate text-[clamp(16px,4.5vw,21px)] font-black tracking-[-.03em] text-white">{value}</div></div>; }
function Nav({ active, children, onClick }: { active: boolean; children: React.ReactNode; onClick: () => void }) { return <button onClick={onClick} className={cls("h-14 rounded-[22px] border px-2 text-[12px] uppercase tracking-[.22em]", active ? "border-amber-100/60 bg-gradient-to-br from-[#fff5bc] to-[#f2b56e] text-[#17110d]" : "border-[#6e4019]/55 bg-[#131115]/92 text-[#c9c1bf]")}>{children}</button>; }
function Button({ children, onClick, active = false, disabled = false }: { children: React.ReactNode; onClick?: () => void; active?: boolean; disabled?: boolean }) { return <button onClick={onClick} disabled={disabled} className={cls("rounded-[18px] border px-4 py-3 text-sm font-semibold disabled:opacity-40", active ? "border-amber-100/60 bg-[#ffe8a1] text-[#15100d]" : "border-[#6d4018]/55 bg-[#0f0e12]/90 text-zinc-200")}>{children}</button>; }
function MoneyInput({ value, setValue }: { value: string; setValue: (value: string) => void }) { return <div className="flex items-center gap-2 rounded-[22px] border border-[#523013]/70 bg-[#0b0a0d] px-5 py-4 text-zinc-400"><span className="text-[#d6a934]">$</span><input value={value} onChange={(e) => setValue(e.target.value)} inputMode="decimal" placeholder="Enter value" className="w-full bg-transparent text-right text-white outline-none placeholder:text-zinc-600" /></div>; }

function PizzaVisual({ plan }: { plan: Plan }) {
  const c = chartState(plan);
  return <div className="relative mx-auto w-full max-w-[320px]">
    <img src={PIZZA_PNG} alt="Pizza allocation chart" className="mx-auto block w-full max-w-[320px] rounded-full object-contain drop-shadow-[0_18px_34px_rgba(0,0,0,.58)]" />
    <div className="pointer-events-none absolute left-1/2 top-1/2 flex h-[28%] w-[28%] -translate-x-1/2 -translate-y-1/2 items-center justify-center rounded-full bg-[#050507]/90 text-center shadow-[0_0_18px_rgba(0,0,0,.65)]">
      <div>
        <div className="text-[clamp(8px,2.1vw,11px)] uppercase tracking-[.22em] text-[#d6a934]">Allocated</div>
        <div className="mt-1 text-[clamp(15px,4vw,21px)] font-black text-white">{money(c.allocated)}</div>
        <div className="text-[clamp(9px,2.4vw,12px)] text-zinc-400">of {money(plan.total)}</div>
      </div>
    </div>
  </div>;
}
function SegmentList({ plan }: { plan: Plan }) { const c = chartState(plan); return <div className="mt-5 overflow-hidden rounded-[23px] border border-[#3d2715]/80 bg-[#0b0a0d]/94">{c.segments.slice(0, 7).map((s) => <div key={s.id} className="flex items-center justify-between gap-3 border-b border-[#3d2715]/65 px-3 py-3 last:border-b-0"><div className="flex min-w-0 items-center gap-3"><Badge topping={s.topping} /><div className="min-w-0"><div className="truncate text-[18px] font-bold text-white">{s.label}</div><div className="truncate text-[15px] text-[#8f8891]">{toppingLabel(s.topping)} - {c.template ? "Template" : pct((s.value / c.total) * 100)}</div></div></div><div className="shrink-0 text-[18px] font-semibold text-white">{money(s.amount)}</div></div>)}</div>; }
function ChartPanel({ plan, title }: { plan: Plan; title: string }) { return <section className="rounded-[34px] border border-[#4a2e17]/80 bg-[#111116]/86 p-4 shadow-[0_22px_55px_rgba(0,0,0,.38)]"><h2 className="text-[25px] font-extrabold text-[#ffb342]">{title}</h2><div className="mt-3"><PizzaVisual plan={plan} /></div><SegmentList plan={plan} /></section>; }

export default function App() {
  const [state, setState] = useState<AppState>(load);
  const [planKey, setPlanKey] = useState<PlanKey>("current");
  const [tab, setTab] = useState<Tab>("chart");
  const [index, setIndex] = useState(0);
  const [amountDraft, setAmountDraft] = useState("");
  const [totalDraft, setTotalDraft] = useState("");
  const plan = state[planKey];
  const chart = useMemo(() => chartState(plan), [plan]);
  const selected = plan.sections[index] ?? null;

  useEffect(() => { localStorage.setItem(STORAGE_KEY, JSON.stringify({ ...state, updatedAt: new Date().toISOString() })); }, [state]);
  useEffect(() => { if (index >= plan.sections.length) setIndex(Math.max(0, plan.sections.length - 1)); setTotalDraft(plan.total ? String(plan.total) : ""); }, [index, plan.sections.length, plan.total]);

  const patchPlan = (key: PlanKey, fn: (plan: Plan) => Plan) => setState((s) => ({ ...s, [key]: fn(s[key]) }));
  const patchSelected = (patch: Partial<Slice>) => selected && patchPlan(planKey, (p) => ({ ...p, sections: p.sections.map((s, i) => s.id === selected.id ? { ...s, ...patch, topping: patch.name && isUnassigned(patch.name) ? "sauce" : patch.topping ?? s.topping ?? normalizeTopping(s.topping, i, s.name) } : s) }));
  const addSection = () => { patchPlan(planKey, (p) => ({ ...p, sections: [...p.sections, { id: uid(), name: `Section ${p.sections.length + 1}`, amount: 0, topping: TOPPINGS[p.sections.length % (TOPPINGS.length - 1)].value }] })); setIndex(plan.sections.length); };
  const deleteSection = () => { if (!selected) return; patchPlan(planKey, (p) => ({ ...p, sections: p.sections.filter((s) => s.id !== selected.id) })); setIndex((i) => Math.max(0, i - 1)); };
  const applyAmount = (mode: "set" | "add" | "subtract") => { if (!selected) return; const n = parseMoney(amountDraft); patchSelected({ amount: mode === "set" ? n : mode === "add" ? selected.amount + n : Math.max(0, selected.amount - n) }); setAmountDraft(""); };
  const copyCurrentToNext = () => setState((s) => ({ ...s, next: { total: s.current.total, sections: s.current.sections.map((x) => ({ ...x, id: uid() })) }, nextEnabled: true }));
  const clearNext = () => setState((s) => ({ ...s, next: { total: 0, sections: [] } }));
  const reset = () => { localStorage.removeItem(STORAGE_KEY); setState(fresh()); setIndex(0); setPlanKey("current"); setTab("chart"); };
  const exportJson = () => { const blob = new Blob([JSON.stringify({ ...state, updatedAt: new Date().toISOString() }, null, 2)], { type: "application/json" }); const url = URL.createObjectURL(blob); const a = document.createElement("a"); a.href = url; a.download = "slice-board-export.json"; a.click(); URL.revokeObjectURL(url); };
  const importJson = async (e: React.ChangeEvent<HTMLInputElement>) => { const file = e.target.files?.[0]; if (!file) return; try { setState(normalizeState(JSON.parse(await file.text()))); setIndex(0); setPlanKey("current"); setTab("chart"); } catch { alert("That JSON could not be imported."); } finally { e.target.value = ""; } };

  return <main className="min-h-screen overflow-x-hidden bg-[#080706] text-white antialiased"><div className="fixed inset-0 -z-10 bg-[radial-gradient(circle_at_18%_6%,rgba(250,204,21,.16),transparent_28%),radial-gradient(circle_at_88%_20%,rgba(194,65,12,.18),transparent_27%),linear-gradient(180deg,#0a0909_0%,#130d08_56%,#080706_100%)]" /><div className="mx-auto flex min-h-screen w-full max-w-[430px] flex-col px-3 pb-5 pt-5">
    <header className="rounded-[32px] border border-[#563519]/75 bg-[#111116]/92 p-4 shadow-[0_22px_50px_rgba(0,0,0,.42)]"><div className="flex items-center gap-4"><Logo /><div className="min-w-0"><h1 className="truncate bg-gradient-to-r from-[#fff2a5] via-[#ffd84e] to-[#ff7a00] bg-clip-text text-[clamp(29px,8.2vw,34px)] font-black leading-none tracking-[-.08em] text-transparent">Slice Board</h1><p className="mt-2 text-[clamp(16px,4.2vw,18px)] text-[#aaa3aa]">Plan your balance.</p></div></div></header>
    <section className="mt-4 grid grid-cols-3 gap-2"><Metric label="Active Pie" value={planKey === "current" ? "Current" : "Next"} /><Metric label="Total" value={money(plan.total)} /><Metric label="Allocated" value={money(chart.allocated)} tone="ember" /></section>
    <div className="mt-4 flex-1">{tab === "chart" && <ChartPanel plan={plan} title={planKey === "current" ? "Current Pie" : "Next Pie"} />}
      {tab === "edit" && <section className="rounded-[34px] border border-[#4a2e17]/80 bg-[#111116]/86 p-4"><div className="flex items-center justify-between"><h2 className="text-[25px] font-extrabold">Edit sections</h2><div className="rounded-full bg-[#0b0a0d] px-4 py-2 text-[12px] uppercase tracking-[.32em] text-[#d6a934]">{plan.sections.length ? index + 1 : 0} / {plan.sections.length}</div></div>{selected ? <><div className="mt-5 flex items-center justify-between"><Button onClick={() => setIndex((i) => i <= 0 ? Math.max(0, plan.sections.length - 1) : i - 1)} disabled={plan.sections.length <= 1}>Prev</Button><Badge topping={normalizeTopping(selected.topping, index, selected.name)} /><Button onClick={() => setIndex((i) => plan.sections.length ? (i + 1) % plan.sections.length : 0)} disabled={plan.sections.length <= 1}>Next</Button></div><div className="mt-5 rounded-[28px] border border-[#3d2715]/80 bg-[#0b0a0d]/92 p-5"><label className="text-[13px] uppercase tracking-[.32em] text-[#d6a934]">Section name</label><input value={selected.name} onChange={(e) => patchSelected({ name: e.target.value })} className="mt-3 w-full rounded-[22px] border border-[#523013]/70 bg-[#09090b] px-5 py-4 text-[18px] text-white outline-none" /><label className="mt-5 block text-[13px] uppercase tracking-[.32em] text-[#d6a934]">Topping identity</label><select disabled={isUnassigned(selected.name)} value={normalizeTopping(selected.topping, index, selected.name) === "sauce" ? "plain" : normalizeTopping(selected.topping, index, selected.name)} onChange={(e) => patchSelected({ topping: e.target.value as Topping })} className="mt-3 w-full rounded-[22px] border border-[#523013]/70 bg-[#09090b] px-5 py-4 text-[18px] text-white outline-none disabled:opacity-70">{TOPPINGS.map((o) => <option key={o.value} value={o.value}>{o.label}</option>)}</select><label className="mt-5 block text-[13px] uppercase tracking-[.32em] text-[#d6a934]">Amount tool</label><div className="mt-3"><MoneyInput value={amountDraft} setValue={setAmountDraft} /></div><div className="mt-4 grid grid-cols-3 gap-2"><Button disabled={!amountDraft} onClick={() => applyAmount("set")}>Change</Button><Button disabled={!amountDraft} onClick={() => applyAmount("add")}>Add</Button><Button disabled={!amountDraft} onClick={() => applyAmount("subtract")}>Subtract</Button></div></div><div className="mt-5 grid grid-cols-2 gap-3"><Button active onClick={addSection}>New section</Button><Button onClick={deleteSection} disabled={plan.sections.length <= 1}>Delete section</Button></div></> : <Button active onClick={addSection}>New section</Button>}</section>}
      {tab === "tools" && <section className="rounded-[34px] border border-[#4a2e17]/80 bg-[#111116]/86 p-4"><h2 className="text-[25px] font-extrabold">Tools</h2><div className="mt-5 grid grid-cols-2 gap-3"><Button active={planKey === "current"} onClick={() => setPlanKey("current")}>Current pie</Button><Button active={planKey === "next"} onClick={() => setPlanKey("next")}>Next pie</Button></div><div className="mt-5 rounded-[28px] border border-[#3d2715]/80 bg-[#0b0a0d]/92 p-5"><label className="text-[13px] uppercase tracking-[.32em] text-[#d6a934]">Total pie value</label><div className="mt-3"><MoneyInput value={totalDraft} setValue={setTotalDraft} /></div><div className="mt-4 grid grid-cols-2 gap-3"><Button active onClick={() => patchPlan(planKey, (p) => ({ ...p, total: parseMoney(totalDraft) }))}>Save total</Button><Button onClick={() => setTotalDraft(plan.total ? String(plan.total) : "")}>Undo draft</Button></div></div><div className="mt-5 grid grid-cols-2 gap-3"><Button onClick={copyCurrentToNext}>Copy current to next</Button><Button onClick={clearNext}>Clear next pie</Button><Button onClick={exportJson}>Export JSON</Button><label className="rounded-[18px] border border-[#6d4018]/55 bg-[#0f0e12]/90 px-4 py-3 text-center text-sm font-semibold text-zinc-200">Import JSON<input type="file" accept="application/json" className="hidden" onChange={importJson} /></label><Button onClick={reset}>Reset app</Button></div></section>}
    </div>
    <nav className="sticky bottom-3 mt-4 grid grid-cols-3 gap-2"><Nav active={tab === "chart"} onClick={() => setTab("chart")}>Chart</Nav><Nav active={tab === "edit"} onClick={() => setTab("edit")}>Edit</Nav><Nav active={tab === "tools"} onClick={() => setTab("tools")}>Tools</Nav></nav>
  </div></main>;
}
